import React from 'react';
import {
  Box,
  Container,
  Typography,
  Button,
  Grid,
  Card,
  CardContent,
  useTheme,
} from '@mui/material';
import {
  LocalHospital,
  People,
  AccessTime,
  MedicalServices,
} from '@mui/icons-material';
import { useNavigate } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const features = [
  {
    icon: <LocalHospital fontSize="large" />,
    title: 'Modern Facilities',
    description: 'State-of-the-art medical equipment and comfortable patient rooms.',
  },
  {
    icon: <People fontSize="large" />,
    title: 'Expert Doctors',
    description: 'Highly qualified and experienced medical professionals.',
  },
  {
    icon: <AccessTime fontSize="large" />,
    title: '24/7 Service',
    description: 'Round-the-clock emergency and medical services.',
  },
  {
    icon: <MedicalServices fontSize="large" />,
    title: 'Comprehensive Care',
    description: 'Wide range of medical specialties and treatment options.',
  },
];

const Home = () => {
  const theme = useTheme();
  const navigate = useNavigate();
  const { user } = useAuth();

  const handleBookAppointment = () => {
    if (!user) {
      navigate('/login');
    } else {
      navigate('/appointments');
    }
  };

  return (
    <Box>
      {/* Hero Section */}
      <Box
        sx={{
          bgcolor: theme.palette.primary.main,
          color: 'white',
          py: 8,
          mb: 6,
          borderRadius: { xs: 0, md: '0 0 2rem 2rem' },
          boxShadow: 3,
        }}
      >
        <Container maxWidth="lg">
          <Grid container spacing={4} alignItems="center">
            <Grid item xs={12} md={6}>
              <Typography 
                variant="h2" 
                gutterBottom
                sx={{
                  fontSize: { xs: '2.5rem', md: '3.5rem' },
                  fontWeight: 700,
                  lineHeight: 1.2,
                }}
              >
                Welcome to Lumbini Nepal Hospital
              </Typography>
              <Typography 
                variant="h5" 
                sx={{ 
                  mb: 4,
                  opacity: 0.9,
                  fontSize: { xs: '1.2rem', md: '1.5rem' },
                }}
              >
                Providing quality healthcare services with compassion and excellence
              </Typography>
              <Box sx={{ display: 'flex', gap: 2, flexWrap: 'wrap' }}>
                <Button
                  variant="contained"
                  color="secondary"
                  size="large"
                  onClick={handleBookAppointment}
                  sx={{
                    py: 1.5,
                    px: 4,
                    fontSize: '1.1rem',
                    fontWeight: 600,
                    '&:hover': {
                      transform: 'translateY(-2px)',
                      boxShadow: 4,
                    },
                    transition: 'all 0.2s',
                  }}
                >
                  Book Appointment
                </Button>
                <Button
                  variant="outlined"
                  color="inherit"
                  size="large"
                  onClick={() => navigate('/doctors')}
                  sx={{
                    py: 1.5,
                    px: 4,
                    fontSize: '1.1rem',
                    fontWeight: 600,
                    borderWidth: 2,
                    '&:hover': {
                      borderWidth: 2,
                      transform: 'translateY(-2px)',
                      boxShadow: 4,
                    },
                    transition: 'all 0.2s',
                  }}
                >
                  Find a Doctor
                </Button>
              </Box>
            </Grid>
            <Grid 
              item 
              xs={12} 
              md={6}
              sx={{
                display: { xs: 'none', md: 'block' }
              }}
            >
              <Box
                sx={{
                  position: 'relative',
                  '&::before': {
                    content: '""',
                    position: 'absolute',
                    top: 0,
                    left: 0,
                    right: 0,
                    bottom: 0,
                    backgroundColor: theme.palette.primary.dark,
                    opacity: 0.1,
                    borderRadius: 2,
                  }
                }}
              >
                <Box
                  component="img"
                  src="/images/hospital-hero.jpg"
                  alt="Hospital"
                  onError={(e) => {
                    e.target.onerror = null;
                    e.target.src = 'https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?ixlib=rb-4.0.3';
                  }}
                  sx={{
                    width: '100%',
                    height: '400px',
                    borderRadius: 2,
                    boxShadow: 3,
                    objectFit: 'cover',
                  }}
                />
              </Box>
            </Grid>
          </Grid>
        </Container>
      </Box>

      {/* Features Section */}
      <Container maxWidth="lg" sx={{ mb: 8 }}>
        <Typography 
          variant="h3" 
          align="center" 
          gutterBottom
          sx={{
            fontWeight: 700,
            mb: 4,
            fontSize: { xs: '2rem', md: '2.5rem' },
          }}
        >
          Why Choose Us
        </Typography>
        <Grid container spacing={4} sx={{ mt: 2 }}>
          {features.map((feature, index) => (
            <Grid item xs={12} sm={6} md={3} key={index}>
              <Card
                sx={{
                  height: '100%',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  textAlign: 'center',
                  p: 3,
                  transition: 'all 0.3s',
                  '&:hover': {
                    transform: 'translateY(-8px)',
                    boxShadow: 4,
                  },
                }}
              >
                <Box 
                  sx={{ 
                    color: theme.palette.primary.main,
                    mb: 2,
                    transform: 'scale(1.2)',
                  }}
                >
                  {feature.icon}
                </Box>
                <CardContent>
                  <Typography 
                    variant="h6" 
                    gutterBottom
                    sx={{ fontWeight: 600 }}
                  >
                    {feature.title}
                  </Typography>
                  <Typography variant="body2" color="text.secondary">
                    {feature.description}
                  </Typography>
                </CardContent>
              </Card>
            </Grid>
          ))}
        </Grid>
      </Container>

      {/* Call to Action Section */}
      <Box
        sx={{
          bgcolor: theme.palette.grey[50],
          py: 8,
          borderRadius: { xs: 0, md: '2rem 2rem 0 0' },
          boxShadow: 'inset 0 2px 8px rgba(0,0,0,0.1)',
        }}
      >
        <Container maxWidth="md">
          <Typography 
            variant="h3" 
            align="center" 
            gutterBottom
            sx={{
              fontWeight: 700,
              fontSize: { xs: '2rem', md: '2.5rem' },
            }}
          >
            Ready to Get Started?
          </Typography>
          <Typography 
            variant="h6" 
            align="center" 
            color="text.secondary" 
            sx={{ 
              mb: 4,
              fontSize: { xs: '1.1rem', md: '1.25rem' },
              maxWidth: '600px',
              mx: 'auto',
            }}
          >
            Schedule your appointment today and experience world-class healthcare
          </Typography>
          <Box sx={{ display: 'flex', justifyContent: 'center' }}>
            <Button
              variant="contained"
              color="primary"
              size="large"
              onClick={handleBookAppointment}
              sx={{
                py: 2,
                px: 6,
                fontSize: '1.2rem',
                fontWeight: 600,
                borderRadius: '2rem',
                '&:hover': {
                  transform: 'translateY(-2px)',
                  boxShadow: 4,
                },
                transition: 'all 0.2s',
              }}
            >
              Book Your Appointment Now
            </Button>
          </Box>
        </Container>
      </Box>
    </Box>
  );
};

export default Home;
